<div class="row g-4"><div class="col-lg-4"><div class="card shadow-sm"><div class="card-body"><h1 class="h4">Create Custom Field</h1><form method="post" action="/portal/custom-fields" class="row g-3"><?=csrf_field()?><div class="col-6"><label class="form-label">Entity</label><select name="entity_type" class="form-select"><?php foreach(['customer','property','lead','estimate','job','invoice','vehicle','equipment','user'] as $v):?><option><?=$v?></option><?php endforeach?></select></div><div class="col-6"><label class="form-label">Type</label><select name="field_type" class="form-select"><?php foreach(['text','textarea','number','date','datetime','checkbox','select','email','phone','url'] as $v):?><option><?=$v?></option><?php endforeach?></select></div><div class="col-12"><label class="form-label">Label</label><input name="label" class="form-control" required></div><div class="col-12"><label class="form-label">Key</label><input name="field_key" class="form-control" placeholder="preferred_gate_location" required></div><div class="col-12"><label class="form-label">Options</label><input name="options" class="form-control" placeholder="Comma-separated for select fields"></div><div class="col-4"><input type="number" name="sort_order" value="100" class="form-control"></div><div class="col-4 form-check mt-2"><input type="checkbox" name="required" class="form-check-input" id="cfr"><label for="cfr" class="form-check-label">Required</label></div><div class="col-4 form-check mt-2"><input type="checkbox" name="active" class="form-check-input" checked id="cfa"><label for="cfa" class="form-check-label">Active</label></div><div class="col-12"><button class="btn btn-primary w-100">Create Field</button></div></form></div></div></div><div class="col-lg-8"><div class="card shadow-sm"><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Entity</th><th>Label</th><th>Key</th><th>Type</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($fields as $f):?><tr><td><?=e($f['entity_type'])?></td><td><?=e($f['label'])?></td><td><code><?=e($f['field_key'])?></code></td><td><?=e($f['field_type'])?></td><td><?=$f['active']?'Active':'Inactive'?></td><td><form method="post" action="/portal/custom-fields/<?=$f['id']?>/toggle"><?=csrf_field()?><button class="btn btn-sm btn-outline-secondary">Toggle</button></form></td></tr><?php endforeach?></tbody></table></div></div></div></div>
